import * as react_jsx_runtime from 'react/jsx-runtime';
import { OTPInput } from 'input-otp';
import * as React from 'react';

/**
 * A one-time password input component. Accessible, unstyled, and customizable.
 *
 * ### Component Props
 *
 * See [input-otp](https://input-otp.rodz.dev) documentation for full details.
 *
 * | Prop                  | Type      | Default |
 * | :-------------------- | :-------- | :------ |
 * | _maxLength_ *(required)* | `number`  | -       |
 * | _containerClassName_  | `string`  | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputOTP maxLength={6}>
 *   <InputOTPGroup>
 *     <InputOTPSlot index={0} />
 *     <InputOTPSlot index={1} />
 *     <InputOTPSlot index={2} />
 *   </InputOTPGroup>
 *   <InputOTPSeparator />
 *   <InputOTPGroup>
 *     <InputOTPSlot index={3} />
 *     <InputOTPSlot index={4} />
 *     <InputOTPSlot index={5} />
 *   </InputOTPGroup>
 * </InputOTP>
 * ```
 */
declare function InputOTP({ className, containerClassName, ...props }: React.ComponentProps<typeof OTPInput> & {
    containerClassName?: string;
}): react_jsx_runtime.JSX.Element;
/**
 * A container that groups multiple `InputOTPSlot` components together visually.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputOTPGroup>
 *   <InputOTPSlot index={0} />
 *   <InputOTPSlot index={1} />
 *   <InputOTPSlot index={2} />
 * </InputOTPGroup>
 * ```
 */
declare function InputOTPGroup({ className, ...props }: React.ComponentProps<'div'>): react_jsx_runtime.JSX.Element;
/**
 * A single character slot within the OTP input. Displays the entered character and a caret when active.
 *
 * ### Component Props
 *
 * | Prop                 | Type     | Default |
 * | :------------------- | :------- | :------ |
 * | _index_ *(required)* | `number` | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputOTPSlot index={0} />
 * ```
 */
declare function InputOTPSlot({ index, className, ...props }: React.ComponentProps<'div'> & {
    index: number;
}): react_jsx_runtime.JSX.Element;
/**
 * A visual separator (dash) placed between `InputOTPGroup` components.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputOTPGroup>...</InputOTPGroup>
 * <InputOTPSeparator />
 * <InputOTPGroup>...</InputOTPGroup>
 * ```
 */
declare function InputOTPSeparator({ ...props }: React.ComponentProps<'div'> & {
    children?: React.ReactNode;
}): react_jsx_runtime.JSX.Element;

export { InputOTP, InputOTPGroup, InputOTPSeparator, InputOTPSlot };
